p.m:
\displaystyle{\begin{aligned}
   14\div \frac{7}{4} 
       \amp = \frac{14}{1} \div \frac{7}{4} \\
       \amp = \frac{14}{1} \cdot \frac{4}{7} \amp \hbox{We can divide 14 and 7 by 7 and made those two values smaller.}\\
       \amp = \frac{2}{1}\cdot\frac{4}{1} \\
       \amp = \frac{2\cdot4}{1 \cdot 1} \\
       \amp = 8
\end{aligned}
    }
